import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type MealType = 'breakfast' | 'lunch' | 'dinner' | 'snack' | 'dessert';
export type Difficulty = 'Easy' | 'Medium' | 'Hard';
export type EffortLevel = 'Low' | 'Medium' | 'High';
export type SpiceLevel = 'None' | 'Mild' | 'Medium' | 'Hot';
export type HouseholdType = 'kids' | 'adults' | 'older adults' | 'mixed';

export interface RecipeCard {
  id: string;
  name: string;
  rationale: string;
  timeMinutes: number;
  difficulty: Difficulty;
  ingredientsUsed: string[];
  extraNeeded: string[];
  kosherSummary?: string;
  warnings: string[];
}

export interface Ingredient {
  item: string;
  amount: string;
}

export interface NutritionEstimate {
  calories: number;
  protein_g: number;
  carbs_g: number;
  fat_g: number;
  sodium_mg: number;
  disclaimer: string;
}

export interface DetailedRecipe {
  name: string;
  servings: number;
  timeMinutes: number;
  ingredients: Ingredient[];
  steps: string[];
  substitutions: string[];
  leftovers: string[];
  nutritionEstimate?: NutritionEstimate;
  warnings: string[];
}

export interface GenerationResponse {
  recipeCards: RecipeCard[];
  selectedRecipe: DetailedRecipe;
}

export interface AppSettings {
  defaultDietaryRestrictions: string[];
  defaultHousehold: HouseholdType;
  defaultSpice: SpiceLevel;
  defaultCuisines: string[];
  defaultEquipment: string[];
  isKosher: boolean;
  kosherStandard: 'Strict' | 'Style';
}

export interface WizardState {
  mealType: MealType;
  servings: number;
  leftovers: boolean;
  timeAvailable: number;
  effortLevel: EffortLevel;
  spiceLevel: SpiceLevel;
  cuisines: string[];
  household: HouseholdType;
  allergies: string[];
  dietaryRestrictions: string[];
  ingredients: string;
  ingredientPhoto?: string;
  equipment: string[];
  avoidList: string[];
  isKosher: boolean;
  kosherStandard: 'Strict' | 'Style';
}

export interface SavedRecipe {
  id: string;
  timestamp: number;
  data: DetailedRecipe;
}

import { MealType, Difficulty, EffortLevel, SpiceLevel, HouseholdType } from './types';

export const MEAL_TYPES: MealType[] = ['breakfast', 'lunch', 'dinner', 'snack', 'dessert'];
export const EFFORT_LEVELS: EffortLevel[] = ['Low', 'Medium', 'High'];
export const SPICE_LEVELS: SpiceLevel[] = ['None', 'Mild', 'Medium', 'Hot'];
export const HOUSEHOLD_TYPES: HouseholdType[] = ['kids', 'adults', 'older adults', 'mixed'];

export const DIETARY_RESTRICTIONS = [
  'Gluten-Free', 'Dairy-Free', 'Vegan', 'Vegetarian', 'Keto', 'Paleo', 'Heart-Healthy', 'Low-Sodium', 'Nut-Free', 'Shellfish-Free'
];

export const CUISINES = [
  'Italian', 'Mexican', 'Chinese', 'Indian', 'Japanese', 'Thai', 'Mediterranean', 'French', 'American', 'Middle Eastern'
];

export const COMMON_EQUIPMENT = [
  'Stove', 'Oven', 'Microwave', 'Air Fryer', 'Slow Cooker', 'Instant Pot', 'Blender', 'Food Processor', 'Toaster'
];

export const DEFAULT_SETTINGS = {
  defaultDietaryRestrictions: [],
  defaultHousehold: 'adults' as HouseholdType,
  defaultSpice: 'Medium' as SpiceLevel,
  defaultCuisines: [],
  defaultEquipment: ['Stove', 'Oven'],
  isKosher: false,
  kosherStandard: 'Style' as const
};

import { AppSettings, SavedRecipe } from '../types';
import { DEFAULT_SETTINGS } from '../constants';

const STORAGE_KEYS = {
  SETTINGS: 'pantrypilot_settings',
  SAVED_RECIPES: 'pantrypilot_saved_recipes',
};

// Check if we should use Firebase mode (placeholder for later integration)
const isFirebaseEnabled = (): boolean => {
  // In a real Vite app, you'd check import.meta.env.VITE_FIREBASE_API_KEY
  // For this XML environment, we focus on localStorage as requested.
  return false; 
};

export const getSettings = (): AppSettings => {
  if (isFirebaseEnabled()) {
    // TODO: Implement Firebase Firestore fetch
  }
  const stored = localStorage.getItem(STORAGE_KEYS.SETTINGS);
  return stored ? JSON.parse(stored) : DEFAULT_SETTINGS;
};

export const saveSettings = (settings: AppSettings): void => {
  if (isFirebaseEnabled()) {
    // TODO: Implement Firebase Firestore save
  }
  localStorage.setItem(STORAGE_KEYS.SETTINGS, JSON.stringify(settings));
};

export const getSavedRecipes = (): SavedRecipe[] => {
  if (isFirebaseEnabled()) {
     // TODO: Implement Firebase Firestore fetch
  }
  const stored = localStorage.getItem(STORAGE_KEYS.SAVED_RECIPES);
  return stored ? JSON.parse(stored) : [];
};

export const saveRecipe = (recipe: SavedRecipe): void => {
  const recipes = getSavedRecipes();
  const updated = [recipe, ...recipes.filter(r => r.id !== recipe.id)];
  if (isFirebaseEnabled()) {
    // TODO: Implement Firebase Firestore collection add
  }
  localStorage.setItem(STORAGE_KEYS.SAVED_RECIPES, JSON.stringify(updated));
};

export const deleteRecipe = (recipeId: string): void => {
  const recipes = getSavedRecipes();
  const updated = recipes.filter(r => r.id !== recipeId);
  localStorage.setItem(STORAGE_KEYS.SAVED_RECIPES, JSON.stringify(updated));
};

import { GoogleGenAI, Type } from "@google/genai";
import { WizardState, GenerationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    recipeCards: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rationale: { type: Type.STRING },
          timeMinutes: { type: Type.NUMBER },
          difficulty: { type: Type.STRING, description: 'Easy|Medium|Hard' },
          ingredientsUsed: { type: Type.ARRAY, items: { type: Type.STRING } },
          extraNeeded: { type: Type.ARRAY, items: { type: Type.STRING } },
          kosherSummary: { type: Type.STRING },
          warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['id', 'name', 'rationale', 'timeMinutes', 'difficulty', 'ingredientsUsed', 'extraNeeded', 'warnings']
      }
    },
    selectedRecipe: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING },
        servings: { type: Type.NUMBER },
        timeMinutes: { type: Type.NUMBER },
        ingredients: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              item: { type: Type.STRING },
              amount: { type: Type.STRING }
            }
          }
        },
        steps: { type: Type.ARRAY, items: { type: Type.STRING } },
        substitutions: { type: Type.ARRAY, items: { type: Type.STRING } },
        leftovers: { type: Type.ARRAY, items: { type: Type.STRING } },
        nutritionEstimate: {
          type: Type.OBJECT,
          properties: {
            calories: { type: Type.NUMBER },
            protein_g: { type: Type.NUMBER },
            carbs_g: { type: Type.NUMBER },
            fat_g: { type: Type.NUMBER },
            sodium_mg: { type: Type.NUMBER },
            disclaimer: { type: Type.STRING }
          }
        },
        warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ['name', 'servings', 'timeMinutes', 'ingredients', 'steps', 'substitutions', 'leftovers', 'warnings']
    }
  },
  required: ['recipeCards', 'selectedRecipe']
};

export const generateRecipes = async (input: WizardState): Promise<GenerationResponse> => {
  const prompt = `
    You are a professional chef and nutritionist AI assistant.
    Generate 3-5 recipe options and one fully detailed featured recipe based on the following constraints:

    - Meal Type: ${input.mealType}
    - Servings: ${input.servings}
    - Leftovers wanted: ${input.leftovers ? 'Yes' : 'No'}
    - Time Available: ${input.timeAvailable} minutes
    - Effort Level: ${input.effortLevel}
    - Spice Preference: ${input.spiceLevel}
    - Preferred Cuisines: ${input.cuisines.join(', ')}
    - Cooking for: ${input.household}
    - Allergies (CRITICAL): ${input.allergies.join(', ')}
    - Dietary Restrictions: ${input.dietaryRestrictions.join(', ')}
    - Ingredients available: ${input.ingredients}
    - Equipment available: ${input.equipment.join(', ')}
    - Avoid these ingredients: ${input.avoidList.join(', ')}
    - Kosher: ${input.isKosher ? `Yes (${input.kosherStandard} standards)` : 'No'}

    SAFETY RULES:
    1. If Kosher is enabled: NEVER suggest pork, shellfish, or mixing meat and dairy in the same recipe.
    2. Provide a kosherSummary (e.g., Meat, Dairy, or Pareve).
    3. Highlight ALLERGENS clearly in the warnings array.
    4. If the user provided obviously non-kosher ingredients while requesting a kosher recipe, warn them and suggest substitutions.
    5. Do not provide medical advice.
    6. If input ingredients are empty, suggest recipes using common pantry staples (flour, eggs, oil, rice, beans).

    OUTPUT FORMAT: Return JSON according to the schema.
  `;

  const model = 'gemini-3-flash-preview';
  const parts: any[] = [{ text: prompt }];

  if (input.ingredientPhoto) {
    parts.push({
      inlineData: {
        data: input.ingredientPhoto.split(',')[1],
        mimeType: 'image/jpeg'
      }
    });
  }

  const result = await ai.models.generateContent({
    model,
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA
    }
  });

  try {
    return JSON.parse(result.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("I had trouble cooking up those recipes. Please try again!");
  }
};

import React, { useState, useEffect } from 'react';
import { WizardState, GenerationResponse, DetailedRecipe, SavedRecipe, AppSettings } from './types';
import { getSettings, getSavedRecipes, saveRecipe, deleteRecipe } from './lib/storage';
import Wizard from './components/Wizard';
import RecipeCards from './components/RecipeCards';
import RecipeDetail from './components/RecipeDetail';
import Settings from './components/Settings';
import SavedRecipes from './components/SavedRecipes';

type View = 'home' | 'wizard' | 'results' | 'detail' | 'settings' | 'saved';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [settings, setSettings] = useState<AppSettings>(getSettings());
  const [generationResults, setGenerationResults] = useState<GenerationResponse | null>(null);
  const [selectedRecipe, setSelectedRecipe] = useState<DetailedRecipe | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleStartWizard = () => {
    setCurrentView('wizard');
    setError(null);
  };

  const handleRecipeGenerated = (data: GenerationResponse) => {
    setGenerationResults(data);
    setCurrentView('results');
    setIsLoading(false);
  };

  const handleSelectRecipe = (recipeId: string) => {
    const card = generationResults?.recipeCards.find(c => c.id === recipeId);
    // If the card selected is the "featured" one already in detailed format, we show it
    // Otherwise, for a real app, we might trigger another specific generation for that card.
    // For this version, the first featured recipe is what we display in detail.
    if (generationResults?.selectedRecipe) {
      setSelectedRecipe(generationResults.selectedRecipe);
      setCurrentView('detail');
    }
  };

  const handleSave = (recipe: DetailedRecipe) => {
    const newSaved: SavedRecipe = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      data: recipe
    };
    saveRecipe(newSaved);
    alert('Recipe saved to your collection!');
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <button 
            onClick={() => setCurrentView('home')} 
            className="text-xl font-bold text-orange-600 flex items-center gap-2"
          >
            <span className="text-2xl">✈️</span> PantryPilot
          </button>
          <div className="flex gap-4">
            <button onClick={() => setCurrentView('saved')} className="text-slate-600 hover:text-orange-600 transition-colors">
              Saved
            </button>
            <button onClick={() => setCurrentView('settings')} className="text-slate-600 hover:text-orange-600 transition-colors">
              Settings
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-8">
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 rounded-xl flex items-center gap-3">
            <span>⚠️</span> {error}
          </div>
        )}

        {currentView === 'home' && (
          <div className="text-center py-12">
            <h1 className="text-4xl font-extrabold text-slate-900 mb-4 leading-tight">
              Turn your pantry into <br/><span className="text-orange-600">culinary masterpieces.</span>
            </h1>
            <p className="text-lg text-slate-600 mb-8 max-w-xl mx-auto">
              Tell us what's in your fridge, your dietary needs, and how much time you have. 
              Our AI sous chef does the rest.
            </p>
            <button 
              onClick={handleStartWizard}
              className="bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 px-10 rounded-full shadow-lg shadow-orange-200 transition-all transform hover:scale-105"
            >
              Get Started
            </button>

            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-6">
               <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="text-3xl mb-3">🥦</div>
                  <h3 className="font-bold mb-2">Smart Ingredients</h3>
                  <p className="text-sm text-slate-500">Snap a photo or type what you have. No waste.</p>
               </div>
               <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="text-3xl mb-3">⚖️</div>
                  <h3 className="font-bold mb-2">Dietary Guided</h3>
                  <p className="text-sm text-slate-500">Kosher, Vegan, Gluten-Free? We've got you covered.</p>
               </div>
               <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="text-3xl mb-3">⚡</div>
                  <h3 className="font-bold mb-2">Quick & Effortless</h3>
                  <p className="text-sm text-slate-500">From 10-min snacks to gourmet dinners.</p>
               </div>
            </div>
          </div>
        )}

        {currentView === 'wizard' && (
          <Wizard 
            settings={settings}
            onComplete={handleRecipeGenerated}
            onLoading={(loading) => setIsLoading(loading)}
            onError={(err) => setError(err)}
            isLoading={isLoading}
          />
        )}

        {currentView === 'results' && generationResults && (
          <RecipeCards 
            cards={generationResults.recipeCards} 
            onSelect={handleSelectRecipe}
            onStartOver={() => setCurrentView('wizard')}
          />
        )}

        {currentView === 'detail' && selectedRecipe && (
          <RecipeDetail 
            recipe={selectedRecipe}
            onSave={() => handleSave(selectedRecipe)}
            onStartOver={() => setCurrentView('wizard')}
          />
        )}

        {currentView === 'settings' && (
          <Settings 
            settings={settings} 
            onSave={(newSettings) => {
              setSettings(newSettings);
              setCurrentView('home');
            }} 
          />
        )}

        {currentView === 'saved' && (
          <SavedRecipes 
            onSelect={(recipe) => {
              setSelectedRecipe(recipe);
              setCurrentView('detail');
            }}
            onDelete={deleteRecipe}
          />
        )}
      </main>

      {isLoading && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl p-8 max-w-sm w-full text-center shadow-2xl">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-4 border-orange-500 border-t-transparent mb-4"></div>
            <h3 className="text-xl font-bold text-slate-900 mb-2">Cooking up ideas...</h3>
            <p className="text-slate-500">Finding the perfect recipe based on your pantry and preferences.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { WizardState, GenerationResponse, AppSettings } from '../types';
import { MEAL_TYPES, EFFORT_LEVELS, SPICE_LEVELS, HOUSEHOLD_TYPES, DIETARY_RESTRICTIONS, CUISINES, COMMON_EQUIPMENT } from '../constants';
import { generateRecipes } from '../lib/recipeModel';

interface WizardProps {
  settings: AppSettings;
  onComplete: (data: GenerationResponse) => void;
  onLoading: (loading: boolean) => void;
  onError: (error: string) => void;
  isLoading: boolean;
}

const Wizard: React.FC<WizardProps> = ({ settings, onComplete, onLoading, onError, isLoading }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<WizardState>({
    mealType: 'dinner',
    servings: 2,
    leftovers: false,
    timeAvailable: 30,
    effortLevel: settings.defaultSpice === 'Medium' ? 'Medium' : 'Low',
    spiceLevel: settings.defaultSpice,
    cuisines: settings.defaultCuisines,
    household: settings.defaultHousehold,
    allergies: [],
    dietaryRestrictions: settings.defaultDietaryRestrictions,
    ingredients: '',
    equipment: settings.defaultEquipment,
    avoidList: [],
    isKosher: settings.isKosher,
    kosherStandard: settings.kosherStandard
  });

  const updateForm = (key: keyof WizardState, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const toggleList = (key: 'cuisines' | 'dietaryRestrictions' | 'equipment' | 'allergies', item: string) => {
    const list = [...(formData[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) list.splice(index, 1);
    else list.push(item);
    updateForm(key, list);
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateForm('ingredientPhoto', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    onLoading(true);
    try {
      const results = await generateRecipes(formData);
      onComplete(results);
    } catch (err: any) {
      onError(err.message || 'Something went wrong');
    } finally {
      onLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100 max-w-2xl mx-auto">
      {/* Progress Bar */}
      <div className="h-2 bg-slate-100 flex">
        {[1, 2, 3].map(i => (
          <div key={i} className={`h-full flex-1 transition-all duration-500 ${step >= i ? 'bg-orange-500' : 'bg-transparent'}`} />
        ))}
      </div>

      <div className="p-8">
        {step === 1 && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">1</span>
              Quick Start
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Meal Type</label>
                <div className="flex flex-wrap gap-2">
                  {MEAL_TYPES.map(m => (
                    <button 
                      key={m}
                      onClick={() => updateForm('mealType', m)}
                      className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${formData.mealType === m ? 'bg-orange-600 border-orange-600 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {m.charAt(0).toUpperCase() + m.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Servings</label>
                <input 
                  type="number" min="1" max="20"
                  value={formData.servings}
                  onChange={(e) => updateForm('servings', parseInt(e.target.value))}
                  className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Time Available (mins)</label>
                <input 
                  type="range" min="10" max="180" step="5"
                  value={formData.timeAvailable}
                  onChange={(e) => updateForm('timeAvailable', parseInt(e.target.value))}
                  className="w-full accent-orange-500"
                />
                <div className="text-right text-xs font-bold text-orange-600 mt-1">{formData.timeAvailable} minutes</div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Spice Level</label>
                <div className="flex flex-wrap gap-2">
                  {SPICE_LEVELS.map(s => (
                    <button 
                      key={s}
                      onClick={() => updateForm('spiceLevel', s)}
                      className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.spiceLevel === s ? 'bg-orange-600 border-orange-600 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Cuisines (Select multiple)</label>
              <div className="flex flex-wrap gap-2">
                {CUISINES.map(c => (
                  <button 
                    key={c}
                    onClick={() => toggleList('cuisines', c)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.cuisines.includes(c) ? 'bg-orange-100 border-orange-400 text-orange-700' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                  >
                    {c}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex items-center gap-3">
              <input 
                type="checkbox" id="leftovers"
                checked={formData.leftovers}
                onChange={(e) => updateForm('leftovers', e.target.checked)}
                className="w-5 h-5 accent-orange-500"
              />
              <label htmlFor="leftovers" className="text-sm font-medium text-slate-700">Include leftover instructions?</label>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">2</span>
              Household & Diet
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Who's it for?</label>
                <div className="flex flex-wrap gap-2">
                  {HOUSEHOLD_TYPES.map(h => (
                    <button 
                      key={h}
                      onClick={() => updateForm('household', h)}
                      className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${formData.household === h ? 'bg-orange-600 border-orange-600 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {h.charAt(0).toUpperCase() + h.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

