interface SettingsProps {
  settings: AppSettings;
  onSave: (settings: AppSettings) => void;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [form, setForm] = useState<AppSettings>({ ...settings });

  const update = (key: keyof AppSettings, val: any) => setForm(f => ({ ...f, [key]: val }));

  const toggle = (key: 'defaultDietaryRestrictions' | 'defaultCuisines' | 'defaultEquipment', item: string) => {
    const list = [...(form[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) list.splice(index, 1);
    else list.push(item);
    update(key, list);
  };

  const handleSave = () => {
    saveSettings(form);
    onSave(form);
    alert('Settings saved!');
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 pb-12">
      <h2 className="text-3xl font-black text-slate-900">Personal Preferences</h2>

      <div className="space-y-8 bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
        <section className="space-y-4">
          <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Cooking Standards</h3>
          <div className="flex flex-col gap-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="font-bold text-slate-800">Kosher Preferences</p>
                <p className="text-xs text-slate-500">Enable strict kosher logic for all recipes</p>
              </div>
              <input 
                type="checkbox" 
                checked={form.isKosher}
                onChange={e => update('isKosher', e.target.checked)}
                className="w-6 h-6 accent-orange-600"
              />
            </div>
            {form.isKosher && (
              <select 
                value={form.kosherStandard}
                onChange={e => update('kosherStandard', e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm"
              >
                <option value="Strict">Strict Glatt Kosher</option>
                <option value="Style">Kosher-Style</option>
              </select>
            )}
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Taste & Household</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-2">Default Household</label>
              <select 
                value={form.defaultHousehold}
                onChange={e => update('defaultHousehold', e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm"
              >
                {HOUSEHOLD_TYPES.map(h => <option key={h} value={h}>{h.charAt(0).toUpperCase() + h.slice(1)}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-2">Spice Tolerance</label>
              <select 
                value={form.defaultSpice}
                onChange={e => update('defaultSpice', e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm"
              >
                {SPICE_LEVELS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Dietary & Favorites</h3>
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-2">Always Apply These Restrictions</label>
            <div className="flex flex-wrap gap-2">
              {DIETARY_RESTRICTIONS.map(d => (
                <button 
                  key={d}
                  onClick={() => toggle('defaultDietaryRestrictions', d)}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${form.defaultDietaryRestrictions.includes(d) ? 'bg-orange-600 text-white' : 'bg-slate-50 text-slate-600 border-slate-200'}`}
