            <div className="flex flex-wrap gap-2">
              {COMMON_EQUIPMENT.map(e => (
                <button 
                  key={e}
                  onClick={() => toggle('defaultEquipment', e)}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${form.defaultEquipment.includes(e) ? 'bg-orange-600 text-white' : 'bg-slate-50 text-slate-600 border-slate-200'}`}
