export const EFFORT_LEVELS: EffortLevel[] = ['Low', 'Medium', 'High'];
export const SPICE_LEVELS: SpiceLevel[] = ['None', 'Mild', 'Medium', 'Hot'];
export const HOUSEHOLD_TYPES: HouseholdType[] = ['kids', 'adults', 'older adults', 'mixed'];
export const KOSHER_TYPES: KosherType[] = ['Meat', 'Dairy', 'Pareve'];

export const DIETARY_RESTRICTIONS = [
  'Gluten-Free', 'Dairy-Free', 'Vegan', 'Vegetarian', 'Keto', 'Paleo', 'Heart-Healthy', 'Low-Sodium', 'Nut-Free', 'Shellfish-Free'
];

export const CUISINES = [
  'Israeli', 'Sephardic', 'Ashkenazi', 
  'Italian (Northern)', 'Italian (Southern)', 
  'Indian (North)', 'Indian (South)',
  'Mexican', 'Chinese (Cantonese)', 'Chinese (Szechuan)', 'Japanese', 'Thai', 
  'Mediterranean', 'French (Bistro)', 'American (Southern)', 'Middle Eastern'
];

export const COMMON_EQUIPMENT = [
  'Stove', 'Oven', 'Microwave', 'Air Fryer', 'Slow Cooker', 'Instant Pot', 'Blender', 'Food Processor', 'Toaster'
];

export const PANTRY_STAPLES = [
  'Olive Oil', 'Vegetable Oil', 'Butter', 'Salt', 'Black Pepper', 'Garlic Powder', 'Onion Powder', 
  'Rice', 'Pasta', 'Flour', 'Sugar', 'Eggs', 'Milk', 'Soy Sauce', 'Honey', 'Vinegar', 'Chicken Broth'
];

export const DEFAULT_SETTINGS = {
  defaultDietaryRestrictions: [],
  defaultHousehold: 'adults' as HouseholdType,
  defaultSpice: 'Medium' as SpiceLevel,
  defaultCuisines: [],
  defaultEquipment: ['Stove', 'Oven'],
  isKosher: false,
  kosherStandard: 'Style' as const,
  defaultKosherType: 'Pareve' as KosherType
};

export type MealType = 'breakfast' | 'lunch' | 'dinner' | 'snack' | 'dessert';
export type Difficulty = 'Easy' | 'Medium' | 'Hard';
export type EffortLevel = 'Low' | 'Medium' | 'High';
export type SpiceLevel = 'None' | 'Mild' | 'Medium' | 'Hot';
export type HouseholdType = 'kids' | 'adults' | 'older adults' | 'mixed';
export type KosherType = 'Meat' | 'Dairy' | 'Pareve' | 'None';

export interface RecipeCard {
  id: string;
  name: string;
  rationale: string;
  timeMinutes: number;
  difficulty: Difficulty;
  ingredientsUsed: string[];
  extraNeeded: string[];
  kosherSummary?: string;
  warnings: string[];
}

export interface Ingredient {
  item: string;
  amount: string;
}

export interface NutritionEstimate {
  calories: number;
  protein_g: number;
  carbs_g: number;
  fat_g: number;
  sodium_mg: number;
  disclaimer: string;
}

export interface DetailedRecipe {
  name: string;
  servings: number;
  timeMinutes: number;
  ingredients: Ingredient[];
  steps: string[];
  substitutions: string[];
  leftovers: string[];
  nutritionEstimate?: NutritionEstimate;
  warnings: string[];
}

export interface GenerationResponse {
  recipeCards: RecipeCard[];
  selectedRecipe: DetailedRecipe;
}

export interface AppSettings {
  defaultDietaryRestrictions: string[];
  defaultHousehold: HouseholdType;
  defaultSpice: SpiceLevel;
  defaultCuisines: string[];
  defaultEquipment: string[];
  isKosher: boolean;
  kosherStandard: 'Strict' | 'Style';
  defaultKosherType: KosherType;
}

export interface WizardState {
  mealType: MealType;
  servings: number;
  leftovers: boolean;
  timeAvailable: number;
  effortLevel: EffortLevel;
  spiceLevel: SpiceLevel;
  cuisines: string[];
  household: HouseholdType;
  allergies: string[];
  dietaryRestrictions: string[];
  ingredients: string;
  pantryStaples: string[];
  ingredientPhoto?: string;
  equipment: string[];
  avoidList: string[];
  isKosher: boolean;
  kosherStandard: 'Strict' | 'Style';
  kosherType: KosherType;
}

export interface SavedRecipe {
  id: string;
  timestamp: number;
  data: DetailedRecipe;
}

import React, { useState } from 'react';
import { WizardState, GenerationResponse, AppSettings } from '../types';
import { MEAL_TYPES, EFFORT_LEVELS, SPICE_LEVELS, HOUSEHOLD_TYPES, DIETARY_RESTRICTIONS, CUISINES, COMMON_EQUIPMENT, KOSHER_TYPES, PANTRY_STAPLES } from '../constants';
import { generateRecipes } from '../lib/recipeModel';

interface WizardProps {
  settings: AppSettings;
  onComplete: (data: GenerationResponse) => void;
  onLoading: (loading: boolean) => void;
  onError: (error: string) => void;
  isLoading: boolean;
}

const MEAT_KEYWORDS = ['beef', 'chicken', 'steak', 'lamb', 'meat', 'turkey', 'veal', 'ground beef', 'ribs', 'bacon', 'ham', 'salmon', 'tuna', 'fish'];
const VEGGIE_KEYWORDS = ['broccoli', 'carrot', 'spinach', 'kale', 'pepper', 'onion', 'garlic', 'potato', 'vegetable', 'greens', 'zucchini', 'tomato', 'cabbage', 'lettuce', 'cucumber', 'cauliflower', 'asparagus', 'beans'];

const Wizard: React.FC<WizardProps> = ({ settings, onComplete, onLoading, onError, isLoading }) => {
  const [step, setStep] = useState(1);
  const [showStaples, setShowStaples] = useState(false);
  const [formData, setFormData] = useState<WizardState>({
    mealType: 'dinner',
    servings: 2,
    leftovers: false,
    timeAvailable: 30,
    effortLevel: settings.defaultSpice === 'Medium' ? 'Medium' : 'Low',
    spiceLevel: settings.defaultSpice,
    cuisines: settings.defaultCuisines,
    household: settings.defaultHousehold,
    allergies: [],
    dietaryRestrictions: settings.defaultDietaryRestrictions,
    ingredients: '',
    pantryStaples: [],
    equipment: settings.defaultEquipment,
    avoidList: [],
    isKosher: settings.isKosher,
    kosherStandard: settings.kosherStandard,
    kosherType: settings.defaultKosherType || 'Pareve'
  });

  const updateForm = (key: keyof WizardState, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const toggleList = (key: 'cuisines' | 'dietaryRestrictions' | 'equipment' | 'allergies' | 'pantryStaples', item: string) => {
    const list = [...(formData[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) list.splice(index, 1);
    else list.push(item);
    updateForm(key, list);
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateForm('ingredientPhoto', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    onLoading(true);
    try {
      const results = await generateRecipes(formData);
      onComplete(results);
    } catch (err: any) {
      onError(err.message || 'Something went wrong');
    } finally {
      onLoading(false);
    }
  };

  const hasMeatInput = MEAT_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k));
  const hasVeggieInput = VEGGIE_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k) || formData.pantryStaples.some(s => s.toLowerCase().includes(k)));
  const showVeggieNudge = hasMeatInput && !hasVeggieInput && formData.ingredients.trim().length > 3;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100 max-w-2xl mx-auto">
      {/* Progress Bar */}
      <div className="h-2 bg-slate-100 flex">
        {[1, 2, 3].map(i => (
          <div key={i} className={`h-full flex-1 transition-all duration-500 ${step >= i ? 'bg-orange-500' : 'bg-transparent'}`} />
        ))}
      </div>

      <div className="p-8">
        {step === 1 && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">1</span>
              Quick Start
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Meal Type</label>
                <div className="flex flex-wrap gap-2">
                  {MEAL_TYPES.map(m => (
                    <button 
                      key={m}
                      onClick={() => updateForm('mealType', m)}
                      className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${formData.mealType === m ? 'bg-orange-600 border-orange-600 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {m.charAt(0).toUpperCase() + m.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Servings</label>
                <input 
                  type="number" min="1" max="20"
                  value={formData.servings}
                  onChange={(e) => updateForm('servings', parseInt(e.target.value))}
                  className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Time Available (mins)</label>
                <input 
                  type="range" min="10" max="180" step="5"
                  value={formData.timeAvailable}
                  onChange={(e) => updateForm('timeAvailable', parseInt(e.target.value))}
                  className="w-full accent-orange-500"
                />
                <div className="text-right text-xs font-bold text-orange-600 mt-1">{formData.timeAvailable} minutes</div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Spice Level</label>
                <div className="flex flex-wrap gap-2">
                  {SPICE_LEVELS.map(s => (
                    <button 
                      key={s}
                      onClick={() => updateForm('spiceLevel', s)}
                      className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.spiceLevel === s ? 'bg-orange-600 border-orange-600 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Cuisines (Select multiple)</label>
              <div className="flex flex-wrap gap-2">
                {CUISINES.map(c => (
                  <button 
                    key={c}
                    onClick={() => toggleList('cuisines', c)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.cuisines.includes(c) ? 'bg-orange-100 border-orange-400 text-orange-700' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                  >
                    {c}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex items-center gap-3">
              <input 
                type="checkbox" id="leftovers"
                checked={formData.leftovers}
                onChange={(e) => updateForm('leftovers', e.target.checked)}
                className="w-5 h-5 accent-orange-500"
              />
              <label htmlFor="leftovers" className="text-sm font-medium text-slate-700">Include leftover instructions?</label>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">2</span>
              Household & Diet
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Who's it for?</label>
                <div className="flex flex-wrap gap-2">
                  {HOUSEHOLD_TYPES.map(h => (
                    <button 
                      key={h}
                      onClick={() => updateForm('household', h)}
                      className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${formData.household === h ? 'bg-orange-600 border-orange-600 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {h.charAt(0).toUpperCase() + h.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

              <div className="bg-blue-50/50 p-4 rounded-2xl border border-blue-100">
                 <div className="flex items-center gap-3 mb-3">
                  <input 
                    type="checkbox" id="isKosher"
                    checked={formData.isKosher}
                    onChange={(e) => updateForm('isKosher', e.target.checked)}
                    className="w-5 h-5 accent-blue-600"
                  />
                  <label htmlFor="isKosher" className="text-sm font-bold text-slate-700">Keeping Kosher?</label>
                </div>
                {formData.isKosher && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                    <div className="pt-2 border-t border-blue-100">
                      <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-2">Required Meal Category</p>
                      <div className="flex gap-2">
                        {KOSHER_TYPES.map(t => (
                          <button 
                            key={t}
                            onClick={() => updateForm('kosherType', t)}
                            className={`flex-1 py-2 rounded-xl text-xs font-bold border transition-all ${formData.kosherType === t ? 'bg-blue-600 border-blue-600 text-white shadow-md shadow-blue-200' : 'bg-white border-slate-200 text-slate-500 hover:border-blue-300'}`}
                          >
                            {t}
                          </button>
                        ))}
                      </div>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-2">Standard</p>
                      <select 
                        value={formData.kosherStandard}
                        onChange={(e) => updateForm('kosherStandard', e.target.value)}
                        className="w-full text-xs p-2.5 border border-slate-200 rounded-xl outline-none bg-white shadow-sm"
                      >
                        <option value="Strict">Strict (Glatt/Cholov Yisroel)</option>
                        <option value="Style">Conservative / Kosher-Style</option>
                      </select>
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Dietary Restrictions</label>
              <div className="flex flex-wrap gap-2">
                {DIETARY_RESTRICTIONS.map(d => (
                  <button 
                    key={d}
                    onClick={() => toggleList('dietaryRestrictions', d)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.dietaryRestrictions.includes(d) ? 'bg-green-100 border-green-400 text-green-700' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                  >
                    {d}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Allergies (Separate by comma)</label>
              <input 
                type="text"
                placeholder="Peanuts, Shellfish, etc."
                className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
                onBlur={(e) => updateForm('allergies', e.target.value.split(',').map(s => s.trim()).filter(Boolean))}
              />
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">3</span>
              Pantry & Equipment
            </h2>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Ingredients (Snap or Type)</label>
              <div className="space-y-3">
                <textarea 
                  value={formData.ingredients}
                  onChange={(e) => updateForm('ingredients', e.target.value)}
                  placeholder="2 chicken breasts, 1 head of broccoli, soy sauce..."
                  className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none resize-none shadow-inner bg-slate-50/50"
                />

                {showVeggieNudge && (
                  <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-2xl animate-in slide-in-from-top-2 shadow-sm">
                    <p className="text-emerald-800 text-sm font-medium">
                      🥗 <span className="font-bold">Pro-tip for Health:</span> Your menu is looking high in protein! Would you like to add some <span className="underline decoration-emerald-300 font-bold italic">vegetables</span> from your crisper to make it a balanced meal?
                    </p>
                  </div>
                )}

                <div className="flex items-center gap-4">
                  <label className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl cursor-pointer transition-colors text-sm font-semibold border border-slate-200">
                    <span className="text-lg">📷</span> {formData.ingredientPhoto ? 'Photo Added!' : 'Snap Ingredients'}
                    <input type="file" accept="image/*" onChange={handlePhotoUpload} className="hidden" />
                  </label>
                  {formData.ingredientPhoto && <button onClick={() => updateForm('ingredientPhoto', undefined)} className="text-red-500 text-xs font-bold underline">Remove photo</button>}
                  <a href="https://www.amazon.com/fresh" target="_blank" rel="noopener noreferrer" className="text-xs font-bold text-blue-600 hover:underline flex items-center gap-1">
                    🛒 Need ingredients? Shop Amazon Fresh
                  </a>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <label className="block text-sm font-semibold text-slate-700">Pantry Staples</label>
                <button 
                  onClick={() => setShowStaples(!showStaples)}
                  className="text-xs font-bold text-orange-600 underline"
                >
                  {showStaples ? 'Hide Essentials' : 'Show Staples Checklist'}
                </button>
              </div>

              {showStaples && (
                <div className="bg-orange-50/30 p-4 rounded-2xl border border-orange-100 grid grid-cols-2 md:grid-cols-3 gap-2 animate-in fade-in">
                  {PANTRY_STAPLES.map(s => (
                    <button 
                      key={s}
                      onClick={() => toggleList('pantryStaples', s)}
                      className={`text-left px-3 py-1.5 rounded-lg text-xs font-medium border transition-all flex items-center gap-2 ${formData.pantryStaples.includes(s) ? 'bg-orange-600 border-orange-600 text-white' : 'bg-white border-slate-200 text-slate-500 hover:border-orange-200'}`}
                    >
                      <span className="text-sm">{formData.pantryStaples.includes(s) ? '✅' : '⬜'}</span> {s}
                    </button>
                  ))}
                  <div className="col-span-full pt-2 border-t border-orange-100/50 mt-1">
                    <p className="text-[10px] text-orange-400 font-bold uppercase italic">Missing staples? Stock your pantry on <a href="https://www.amazon.com" target="_blank" className="underline">Amazon</a></p>
                  </div>
                </div>
              )}
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Equipment Available</label>
              <div className="flex flex-wrap gap-2">
                {COMMON_EQUIPMENT.map(e => (
                  <button 
                    key={e}
                    onClick={() => toggleList('equipment', e)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.equipment.includes(e) ? 'bg-slate-800 border-slate-800 text-white' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                  >
                    {e}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Footer Navigation */}
        <div className="mt-10 flex justify-between items-center pt-6 border-t border-slate-100">
          {step > 1 && (
            <button 
              onClick={() => setStep(s => s - 1)}
              className="text-slate-500 font-bold hover:text-slate-800 transition-colors"
            >
              Back
            </button>
          )}
          <div className="flex-1" />
          {step < 3 ? (
            <button 
              onClick={() => setStep(s => s + 1)}
              className="bg-orange-600 text-white font-bold py-3 px-8 rounded-full shadow-lg shadow-orange-200 hover:bg-orange-700 transition-all"
            >
              Next Step
            </button>
          ) : (
            <button 
              onClick={handleSubmit}
              disabled={isLoading}
              className="bg-orange-600 text-white font-extrabold py-3 px-10 rounded-full shadow-lg shadow-orange-200 hover:bg-orange-700 transition-all disabled:opacity-50"
            >
              {isLoading ? 'Generating...' : 'Cook My Recipes!'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Wizard;

import { GoogleGenAI, Type } from "@google/genai";
import { WizardState, GenerationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    recipeCards: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rationale: { type: Type.STRING },
          timeMinutes: { type: Type.NUMBER },
          difficulty: { type: Type.STRING, description: 'Easy|Medium|Hard' },
          ingredientsUsed: { type: Type.ARRAY, items: { type: Type.STRING } },
          extraNeeded: { type: Type.ARRAY, items: { type: Type.STRING } },
          kosherSummary: { type: Type.STRING },
          warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['id', 'name', 'rationale', 'timeMinutes', 'difficulty', 'ingredientsUsed', 'extraNeeded', 'warnings']
      }
    },
    selectedRecipe: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING },
        servings: { type: Type.NUMBER },
        timeMinutes: { type: Type.NUMBER },
        ingredients: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              item: { type: Type.STRING },
              amount: { type: Type.STRING }
            }
          }
        },
        steps: { type: Type.ARRAY, items: { type: Type.STRING } },
        substitutions: { type: Type.ARRAY, items: { type: Type.STRING } },
        leftovers: { type: Type.ARRAY, items: { type: Type.STRING } },
        nutritionEstimate: {
          type: Type.OBJECT,
          properties: {
            calories: { type: Type.NUMBER },
            protein_g: { type: Type.NUMBER },
            carbs_g: { type: Type.NUMBER },
            fat_g: { type: Type.NUMBER },
            sodium_mg: { type: Type.NUMBER },
            disclaimer: { type: Type.STRING }
          }
        },
        warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ['name', 'servings', 'timeMinutes', 'ingredients', 'steps', 'substitutions', 'leftovers', 'warnings']
    }
  },
  required: ['recipeCards', 'selectedRecipe']
};

export const generateRecipes = async (input: WizardState): Promise<GenerationResponse> => {
  const prompt = `
    You are a professional chef and nutritionist AI assistant.
    Generate 3-5 recipe options and one fully detailed featured recipe based on the following constraints:

    - Meal Type: ${input.mealType}
    - Servings: ${input.servings}
    - Leftovers wanted: ${input.leftovers ? 'Yes' : 'No'}
    - Time Available: ${input.timeAvailable} minutes
    - Effort Level: ${input.effortLevel}
    - Spice Preference: ${input.spiceLevel}
    - Preferred Cuisines: ${input.cuisines.join(', ')}
    - Cooking for: ${input.household}
    - Allergies (CRITICAL): ${input.allergies.join(', ')}
    - Dietary Restrictions: ${input.dietaryRestrictions.join(', ')}
    - Ingredients on hand: ${input.ingredients}
    - Pantry staples available: ${input.pantryStaples.join(', ')}
    - Equipment available: ${input.equipment.join(', ')}
    - Avoid these ingredients: ${input.avoidList.join(', ')}
    - Kosher: ${input.isKosher ? `Yes (${input.kosherStandard} standards)` : 'No'}
    ${input.isKosher ? `- Required Kosher Category: ${input.kosherType}` : ''}

    SAFETY RULES:
    1. If Kosher is enabled: NEVER suggest pork, shellfish, or mixing meat and dairy in the same recipe.
    2. Strictly follow the required Kosher Category: ${input.kosherType}. 
       - If 'Meat', no dairy allowed.
       - If 'Dairy', no meat allowed.
       - If 'Pareve', neither meat nor dairy allowed (except fish and eggs).
    3. Provide a kosherSummary (e.g., Meat, Dairy, or Pareve).
    4. Highlight ALLERGENS clearly in the warnings array.
    5. If the user provided obviously non-kosher ingredients while requesting a kosher recipe, warn them and suggest substitutions.
    6. Do not provide medical advice.
    7. Prioritize healthy options with vegetables. If the user provided many meats, suggest recipes that incorporate the vegetables effectively or suggest missing common veggies in "extraNeeded".

    OUTPUT FORMAT: Return JSON according to the schema.
  `;

  const model = 'gemini-3-flash-preview';
  const parts: any[] = [{ text: prompt }];

  if (input.ingredientPhoto) {
    parts.push({
      inlineData: {
        data: input.ingredientPhoto.split(',')[1],
        mimeType: 'image/jpeg'
      }
    });
  }

  const result = await ai.models.generateContent({
    model,
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA
    }
  });

  try {
    return JSON.parse(result.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("I had trouble cooking up those recipes. Please try again!");
  }
};

