import { GoogleGenAI, Type } from "@google/genai";
import { WizardState, GenerationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    recipeCards: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rationale: { type: Type.STRING },
          timeMinutes: { type: Type.NUMBER },
          difficulty: { type: Type.STRING, description: 'Easy|Medium|Hard' },
          ingredientsUsed: { type: Type.ARRAY, items: { type: Type.STRING } },
          extraNeeded: { type: Type.ARRAY, items: { type: Type.STRING } },
          kosherSummary: { type: Type.STRING },
          warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['id', 'name', 'rationale', 'timeMinutes', 'difficulty', 'ingredientsUsed', 'extraNeeded', 'warnings']
      }
    },
    selectedRecipe: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING },
        servings: { type: Type.NUMBER },
        timeMinutes: { type: Type.NUMBER },
        ingredients: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              item: { type: Type.STRING },
              amount: { type: Type.STRING }
            }
          }
        },
        steps: { type: Type.ARRAY, items: { type: Type.STRING } },
        substitutions: { type: Type.ARRAY, items: { type: Type.STRING } },
        leftovers: { type: Type.ARRAY, items: { type: Type.STRING } },
        nutritionEstimate: {
          type: Type.OBJECT,
          properties: {
            calories: { type: Type.NUMBER },
            protein_g: { type: Type.NUMBER },
            carbs_g: { type: Type.NUMBER },
            fat_g: { type: Type.NUMBER },
            sodium_mg: { type: Type.NUMBER },
            disclaimer: { type: Type.STRING }
          }
        },
        warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ['name', 'servings', 'timeMinutes', 'ingredients', 'steps', 'substitutions', 'leftovers', 'warnings']
    }
  },
  required: ['recipeCards', 'selectedRecipe']
};

export const generateRecipes = async (input: WizardState): Promise<GenerationResponse> => {
  const prompt = `
    You are a professional chef and nutritionist AI assistant.
    Generate 3-5 recipe options and one fully detailed featured recipe based on the following constraints:

    - Meal Type: ${input.mealType}
    - Servings: ${input.servings}
    - Leftovers wanted: ${input.leftovers ? 'Yes' : 'No'}
    - Time Available: ${input.timeAvailable} minutes
    - Effort Level: ${input.effortLevel}
    - Spice Preference: ${input.spiceLevel}
    - Preferred Cuisines: ${input.cuisines.join(', ')}
    - User Skill Level: ${input.skillLevel} (tailor complexity of steps to this level)
    - Stylistic Inspiration: ${input.favoriteChef ? `Model style after ${input.favoriteChef}` : 'Professional Home Chef'}
    - Cooking for: ${input.household}
    - Allergies (CRITICAL): ${input.allergies.join(', ')}
    - Dietary Restrictions: ${input.dietaryRestrictions.join(', ')}
    - Ingredients on hand: ${input.ingredients}
    - Pantry staples available: ${input.pantryStaples.join(', ')}
    - Equipment available: ${input.equipment.join(', ')}
    - Avoid these ingredients: ${input.avoidList.join(', ')}
    - Kosher: ${input.isKosher ? `Yes (${input.kosherStandard} standards)` : 'No'}
    ${input.isKosher ? `- Required Kosher Category: ${input.kosherType}` : ''}

    SAFETY RULES:
    1. If Kosher is enabled: NEVER suggest pork, shellfish, or mixing meat and dairy in the same recipe.
    2. Strictly follow the required Kosher Category: ${input.kosherType}. 
       - If 'Meat', no dairy allowed.
       - If 'Dairy', no meat allowed.
       - If 'Pareve', neither meat nor dairy allowed (except fish and eggs).
    3. Provide a kosherSummary (e.g., Meat, Dairy, or Pareve).
    4. Highlight ALLERGENS clearly in the warnings array.
    5. If the user provided obviously non-kosher ingredients while requesting a kosher recipe, warn them and suggest substitutions.
    6. Do not provide medical advice.
    7. Prioritize healthy options with vegetables. If the user provided many meats, suggest recipes that incorporate the vegetables effectively or suggest missing common veggies in "extraNeeded".

    OUTPUT FORMAT: Return JSON according to the schema.
  `;

  const model = 'gemini-3-flash-preview';
  const parts: any[] = [{ text: prompt }];

  if (input.ingredientPhoto) {
    parts.push({
      inlineData: {
        data: input.ingredientPhoto.split(',')[1],
        mimeType: 'image/jpeg'
      }
    });
  }

  const result = await ai.models.generateContent({
    model,
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA
    }
  });

  try {
    return JSON.parse(result.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("I had trouble cooking up those recipes. Please try again!");
  }
};

import React, { useState, useEffect } from 'react';
import { WizardState, GenerationResponse, DetailedRecipe, SavedRecipe, AppSettings } from './types';
import { getSettings, getSavedRecipes, saveRecipe, deleteRecipe } from './lib/storage';
import Wizard from './components/Wizard';
import RecipeCards from './components/RecipeCards';
import RecipeDetail from './components/RecipeDetail';
import Settings from './components/Settings';
import SavedRecipes from './components/SavedRecipes';

type View = 'home' | 'wizard' | 'results' | 'detail' | 'settings' | 'saved';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>(getSettings());
  const [currentView, setCurrentView] = useState<View>(settings.hasOnboarded ? 'home' : 'settings');
  const [generationResults, setGenerationResults] = useState<GenerationResponse | null>(null);
  const [selectedRecipe, setSelectedRecipe] = useState<DetailedRecipe | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleStartWizard = () => {
    setCurrentView('wizard');
    setError(null);
  };

  const handleRecipeGenerated = (data: GenerationResponse) => {
    setGenerationResults(data);
    setCurrentView('results');
    setIsLoading(false);
  };

  const handleSelectRecipe = (recipeId: string) => {
    if (generationResults?.selectedRecipe) {
      setSelectedRecipe(generationResults.selectedRecipe);
      setCurrentView('detail');
    }
  };

  const handleSave = (recipe: DetailedRecipe) => {
    const newSaved: SavedRecipe = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      data: recipe
    };
    saveRecipe(newSaved);
    alert('Recipe saved to your collection!');
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <button 
            onClick={() => setCurrentView('home')} 
            className="text-xl font-bold text-orange-600 flex items-center gap-2"
          >
            <span className="text-2xl">✈️</span> PantryPilot
          </button>
          <div className="flex gap-4 items-center">
            {settings.hasOnboarded && (
              <>
                <button onClick={() => setCurrentView('saved')} className="text-slate-600 hover:text-orange-600 transition-colors text-sm font-semibold">
                  Saved
                </button>
                <button onClick={() => setCurrentView('settings')} className="text-slate-600 hover:text-orange-600 transition-colors text-sm font-semibold flex items-center gap-1">
                  <span>⚙️</span> {settings.name || 'Profile'}
                </button>
              </>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-8">
        {!settings.hasOnboarded && (
          <div className="mb-8 p-4 bg-orange-50 border border-orange-200 rounded-2xl">
            <h2 className="text-orange-800 font-bold mb-1">Welcome to PantryPilot! 👩‍🍳</h2>
            <p className="text-sm text-orange-700">Let's set up your profile first so we can tailor recipes just for you.</p>
          </div>
        )}

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 rounded-xl flex items-center gap-3">
            <span>⚠️</span> {error}
          </div>
        )}

        {currentView === 'home' && (
          <div className="text-center py-12">
            <h1 className="text-4xl font-extrabold text-slate-900 mb-4 leading-tight">
              Hello, {settings.name || 'Chef'}! <br/>Ready to <span className="text-orange-600">transform your pantry?</span>
            </h1>
            <p className="text-lg text-slate-600 mb-8 max-w-xl mx-auto">
              Your preferences are pre-filled based on your profile. Just tell us what ingredients you have!
            </p>
            <button 
              onClick={handleStartWizard}
              className="bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 px-10 rounded-full shadow-lg shadow-orange-200 transition-all transform hover:scale-105"
            >
              Start Cooking
            </button>

            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-6 text-left">
               <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="text-3xl mb-3">🥦</div>
                  <h3 className="font-bold mb-2">Smart Veggie Nudge</h3>
                  <p className="text-sm text-slate-500">We'll help you balance your meals with healthy greens.</p>
               </div>
               <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="text-3xl mb-3">✡️</div>
                  <h3 className="font-bold mb-2">Kosher Logic</h3>
                  <p className="text-sm text-slate-500">Built-in Meat/Dairy/Pareve separation for strict adherence.</p>
               </div>
               <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="text-3xl mb-3">🛒</div>
                  <h3 className="font-bold mb-2">Pantry Essentials</h3>
                  <p className="text-sm text-slate-500">Check off staples and shop Amazon for missing items.</p>
