        {currentView === 'detail' && selectedRecipe && (
          <RecipeDetail 
            recipe={selectedRecipe}
            onSave={() => handleSave(selectedRecipe)}
            onStartOver={() => setCurrentView('wizard')}
          />
        )}

        {currentView === 'settings' && (
          <Settings 
            settings={settings} 
            onSave={(newSettings) => {
              setSettings(newSettings);
              setCurrentView('home');
            }} 
          />
        )}

        {currentView === 'saved' && (
          <SavedRecipes 
            onSelect={(recipe) => {
              setSelectedRecipe(recipe);
              setCurrentView('detail');
            }}
            onDelete={deleteRecipe}
          />
        )}
      </main>

      {isLoading && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl p-8 max-w-sm w-full text-center shadow-2xl">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-4 border-orange-500 border-t-transparent mb-4"></div>
            <h3 className="text-xl font-bold text-slate-900 mb-2">Consulting the Chefs...</h3>
            <p className="text-slate-500">Crafting personalized recipes tailored to your {settings.skillLevel} skill level.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { WizardState, GenerationResponse, AppSettings } from '../types';
import { MEAL_TYPES, EFFORT_LEVELS, SPICE_LEVELS, HOUSEHOLD_TYPES, DIETARY_RESTRICTIONS, CUISINE_REGIONS, COMMON_EQUIPMENT, KOSHER_TYPES, PANTRY_STAPLES } from '../constants';
import { generateRecipes } from '../lib/recipeModel';

interface WizardProps {
  settings: AppSettings;
  onComplete: (data: GenerationResponse) => void;
  onLoading: (loading: boolean) => void;
  onError: (error: string) => void;
  isLoading: boolean;
}

const MEAT_KEYWORDS = ['beef', 'chicken', 'steak', 'lamb', 'meat', 'turkey', 'veal', 'ground beef', 'ribs', 'bacon', 'ham', 'salmon', 'tuna', 'fish'];
const VEGGIE_KEYWORDS = ['broccoli', 'carrot', 'spinach', 'kale', 'pepper', 'onion', 'garlic', 'potato', 'vegetable', 'greens', 'zucchini', 'tomato', 'cabbage', 'lettuce', 'cucumber', 'cauliflower', 'asparagus', 'beans'];

const Wizard: React.FC<WizardProps> = ({ settings, onComplete, onLoading, onError, isLoading }) => {
  const [step, setStep] = useState(1);
  const [showStaples, setShowStaples] = useState(false);
  const [formData, setFormData] = useState<WizardState>({
    mealType: 'dinner',
    servings: 2,
    leftovers: false,
    timeAvailable: 30,
    effortLevel: 'Medium',
    spiceLevel: settings.defaultSpice,
    cuisines: settings.defaultCuisines,
    household: settings.defaultHousehold,
    allergies: [],
    dietaryRestrictions: settings.defaultDietaryRestrictions,
    ingredients: '',
    pantryStaples: [],
    equipment: settings.defaultEquipment,
    avoidList: [],
    isKosher: settings.isKosher,
    kosherStandard: settings.kosherStandard,
    kosherType: settings.defaultKosherType || 'Pareve',
    skillLevel: settings.skillLevel,
    favoriteChef: settings.favoriteChef
  });

  const updateForm = (key: keyof WizardState, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const toggleList = (key: 'cuisines' | 'dietaryRestrictions' | 'equipment' | 'allergies' | 'pantryStaples', item: string) => {
    const list = [...(formData[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) list.splice(index, 1);
    else list.push(item);
    updateForm(key, list);
  };

  const handleSelectAllStaples = () => {
    if (formData.pantryStaples.length === PANTRY_STAPLES.length) {
      updateForm('pantryStaples', []);
    } else {
      updateForm('pantryStaples', [...PANTRY_STAPLES]);
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateForm('ingredientPhoto', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    onLoading(true);
    try {
      const results = await generateRecipes(formData);
      onComplete(results);
    } catch (err: any) {
      onError(err.message || 'Something went wrong');
    } finally {
      onLoading(false);
    }
  };

  const hasMeatInput = MEAT_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k));
  const hasVeggieInput = VEGGIE_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k) || formData.pantryStaples.some(s => s.toLowerCase().includes(k)));
  const showVeggieNudge = hasMeatInput && !hasVeggieInput && formData.ingredients.trim().length > 3;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100 max-w-2xl mx-auto">
      {/* Progress Bar */}
      <div className="h-2 bg-slate-100 flex">
        {[1, 2, 3].map(i => (
          <div key={i} className={`h-full flex-1 transition-all duration-500 ${step >= i ? 'bg-orange-500' : 'bg-transparent'}`} />
        ))}
      </div>

      <div className="p-8">
        {step === 1 && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">1</span>
              Quick Start
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Meal Type</label>
                <div className="flex flex-wrap gap-2">
                  {MEAL_TYPES.map(m => (
                    <button 
                      key={m}
                      onClick={() => updateForm('mealType', m)}
                      className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${formData.mealType === m ? 'bg-orange-600 border-orange-600 text-white shadow-md shadow-orange-100' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {m.charAt(0).toUpperCase() + m.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Servings</label>
                <input 
                  type="number" min="1" max="20"
                  value={formData.servings}
                  onChange={(e) => updateForm('servings', parseInt(e.target.value))}
                  className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Time Available (mins)</label>
                <input 
                  type="range" min="10" max="180" step="5"
                  value={formData.timeAvailable}
                  onChange={(e) => updateForm('timeAvailable', parseInt(e.target.value))}
                  className="w-full accent-orange-500"
                />
