              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Spice Level</label>
                <div className="flex flex-wrap gap-2">
                  {SPICE_LEVELS.map(s => (
                    <button 
                      key={s}
                      onClick={() => updateForm('spiceLevel', s)}
                      className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.spiceLevel === s ? 'bg-orange-600 border-orange-600 text-white shadow-md shadow-orange-100' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-4">Cuisines (By Region)</label>
              <div className="space-y-4">
                {Object.entries(CUISINE_REGIONS).map(([region, items]) => (
                  <div key={region} className="space-y-2">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{region}</p>
                    <div className="flex flex-wrap gap-2">
                      {items.map(c => (
                        <button 
                          key={c}
                          onClick={() => toggleList('cuisines', c)}
