                    key={e}
                    onClick={() => toggleList('equipment', e)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.equipment.includes(e) ? 'bg-slate-800 border-slate-800 text-white shadow-sm' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                  >
                    {e}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Footer Navigation */}
        <div className="mt-10 flex justify-between items-center pt-6 border-t border-slate-100">
          {step > 1 && (
            <button 
              onClick={() => setStep(s => s - 1)}
              className="text-slate-500 font-bold hover:text-slate-800 transition-colors"
            >
