import React, { useState, useEffect } from 'react';
import { WizardState, GenerationResponse, DetailedRecipe, SavedRecipe, AppSettings } from './types';
import { getSettings, getSavedRecipes, saveRecipe, deleteRecipe } from './lib/storage';
import Wizard from './components/Wizard';
import RecipeCards from './components/RecipeCards';
import RecipeDetail from './components/RecipeDetail';
import Settings from './components/Settings';
import SavedRecipes from './components/SavedRecipes';

type View = 'home' | 'wizard' | 'results' | 'detail' | 'settings' | 'saved';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>(getSettings());
  const [currentView, setCurrentView] = useState<View>('home');
  const [generationResults, setGenerationResults] = useState<GenerationResponse | null>(null);
  const [selectedRecipe, setSelectedRecipe] = useState<DetailedRecipe | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleStartWizard = () => {
    setCurrentView('wizard');
    setError(null);
  };

  const handleRecipeGenerated = (data: GenerationResponse) => {
    setGenerationResults(data);
    setCurrentView('results');
    setIsLoading(false);
  };

  const handleSelectRecipe = (recipeId: string) => {
    if (generationResults?.selectedRecipe) {
      setSelectedRecipe(generationResults.selectedRecipe);
      setCurrentView('detail');
    }
  };

  const handleSave = (recipe: DetailedRecipe) => {
    const newSaved: SavedRecipe = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      data: recipe
    };
    saveRecipe(newSaved);
    alert('Recipe saved to your collection!');
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <button 
            onClick={() => setCurrentView('home')} 
            className="text-xl font-bold text-orange-600 flex items-center gap-2"
          >
            <span className="text-2xl">✈️</span> PantryPilot
          </button>
          <div className="flex gap-4 items-center">
            <button onClick={() => setCurrentView('saved')} className="text-slate-600 hover:text-orange-600 transition-colors text-sm font-semibold">
              My Saves
            </button>
            <button onClick={() => setCurrentView('settings')} className="text-slate-600 hover:text-orange-600 transition-colors text-sm font-semibold flex items-center gap-1">
              <span>⚙️</span> Preferences
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-8">
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 rounded-xl flex items-center gap-3">
            <span>⚠️</span> {error}
          </div>
        )}

        {currentView === 'home' && (
          <div className="text-center py-12 flex flex-col items-center">
            <div className="mb-6 p-3 bg-orange-100 rounded-full inline-block animate-bounce">
              <span className="text-3xl">👨‍🍳</span>
            </div>
            <h1 className="text-5xl font-extrabold text-slate-900 mb-6 leading-tight max-w-2xl">
              Turn your ingredients into <span className="text-orange-600">gourmet meals</span> in seconds.
            </h1>
            <p className="text-xl text-slate-500 mb-10 max-w-xl">
              Tell us what's in your pantry and we'll handle the culinary logic, religious requirements, and health goals.
            </p>
            <button 
              onClick={handleStartWizard}
              className="bg-orange-600 hover:bg-orange-700 text-white text-xl font-black py-5 px-14 rounded-full shadow-2xl shadow-orange-200 transition-all transform hover:scale-105 active:scale-95 mb-16"
            >
              Start My Meal Quiz
            </button>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 text-left w-full">
               <div className="p-8 bg-white rounded-3xl shadow-sm border border-slate-100 hover:border-orange-200 transition-colors group">
                  <div className="text-4xl mb-4 group-hover:scale-110 transition-transform">🥑</div>
                  <h3 className="font-bold text-lg mb-2">Smart Health</h3>
                  <p className="text-sm text-slate-500 leading-relaxed">Anti-inflammatory, Keto, or Heart-Healthy? We nudge you toward better nutrition.</p>
               </div>
               <div className="p-8 bg-white rounded-3xl shadow-sm border border-slate-100 hover:border-blue-200 transition-colors group">
                  <div className="text-4xl mb-4 group-hover:scale-110 transition-transform">✡️</div>
                  <h3 className="font-bold text-lg mb-2">Religious Logic</h3>
                  <p className="text-sm text-slate-500 leading-relaxed">Built-in separation for Kosher (Meat/Dairy/Pareve), Halal, and Jain diets.</p>
               </div>
               <div className="p-8 bg-white rounded-3xl shadow-sm border border-slate-100 hover:border-emerald-200 transition-colors group">
                  <div className="text-4xl mb-4 group-hover:scale-110 transition-transform">📸</div>
                  <h3 className="font-bold text-lg mb-2">Photo Scan</h3>
                  <p className="text-sm text-slate-500 leading-relaxed">Don't want to type? Snap a photo of your fridge and our AI will identify the ingredients.</p>
               </div>
            </div>
          </div>
        )}

        {currentView === 'wizard' && (
          <Wizard 
            settings={settings}
            onComplete={handleRecipeGenerated}
            onLoading={(loading) => setIsLoading(loading)}
            onError={(err) => setError(err)}
            isLoading={isLoading}
          />
        )}

        {currentView === 'results' && generationResults && (
          <RecipeCards 
            cards={generationResults.recipeCards} 
            onSelect={handleSelectRecipe}
            onStartOver={() => setCurrentView('wizard')}
          />
        )}

        {currentView === 'detail' && selectedRecipe && (
          <RecipeDetail 
            recipe={selectedRecipe}
            onSave={() => handleSave(selectedRecipe)}
            onStartOver={() => setCurrentView('results')}
          />
        )}

        {currentView === 'settings' && (
          <Settings 
            settings={settings} 
            onSave={(newSettings) => {
              setSettings(newSettings);
              setCurrentView('home');
            }} 
          />
        )}

        {currentView === 'saved' && (
          <SavedRecipes 
            onSelect={(recipe) => {
              setSelectedRecipe(recipe);
              setCurrentView('detail');
            }}
            onDelete={deleteRecipe}
          />
        )}
      </main>

      {isLoading && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full text-center shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="inline-block animate-spin rounded-full h-16 w-16 border-4 border-orange-500 border-t-transparent mb-6"></div>
            <h3 className="text-2xl font-black text-slate-900 mb-2">Chef is thinking...</h3>
            <p className="text-slate-500 font-medium">Crafting custom {settings.isKosher ? 'Kosher' : ''} recipes specifically for your skill level.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AppSettings, HouseholdType, SpiceLevel, KosherType, SkillLevel } from '../types';
import { HOUSEHOLD_TYPES, SPICE_LEVELS, HEALTH_DIETS, RELIGIOUS_DIETS, CUISINE_REGIONS, COMMON_EQUIPMENT, KOSHER_STANDARDS, SKILL_LEVELS } from '../constants';
import { saveSettings } from '../lib/storage';

interface SettingsProps {
  settings: AppSettings;
  onSave: (settings: AppSettings) => void;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [form, setForm] = useState<AppSettings>({ ...settings });

  const update = (key: keyof AppSettings, val: any) => setForm(f => ({ ...f, [key]: val }));

  const toggle = (key: 'defaultDietaryRestrictions' | 'defaultCuisines' | 'defaultEquipment', item: string) => {
    const list = [...(form[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) {
      list.splice(index, 1);
      if (item === 'Kosher' && key === 'defaultDietaryRestrictions') update('isKosher', false);
    } else {
      list.push(item);
      if (item === 'Kosher' && key === 'defaultDietaryRestrictions') update('isKosher', true);
    }
    update(key, list);
  };

  const handleSave = () => {
    const finalForm = { ...form, hasOnboarded: true };
    saveSettings(finalForm);
    onSave(finalForm);
    alert('Preferences saved! We will use these for your future searches.');
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 pb-12 animate-in fade-in duration-500">
      <div className="text-center mb-10">
        <h2 className="text-4xl font-black text-slate-900 mb-2">My Kitchen Profile</h2>
        <p className="text-slate-500">Optional: Set these defaults to skip steps in the meal quiz.</p>
      </div>

      <div className="space-y-8 bg-white p-8 md:p-10 rounded-[2.5rem] shadow-sm border border-slate-100">
        <section className="space-y-6">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-2">The Basics</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Your Name</label>
              <input 
                type="text" 
                value={form.name || ''} 
                onChange={e => update('name', e.target.value)}
                placeholder="Chef"
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none text-sm focus:ring-2 focus:ring-orange-500"
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Skill Level</label>
              <select 
                value={form.skillLevel}
                onChange={e => update('skillLevel', e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none text-sm"
              >
                {SKILL_LEVELS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div className="col-span-full">
              <label className="block text-sm font-bold text-slate-700 mb-2">Favorite Chef (Style Inspiration)</label>
              <input 
                type="text" 
                value={form.favoriteChef || ''} 
                onChange={e => update('favoriteChef', e.target.value)}
                placeholder="Ina Garten, Jamie Oliver, etc."
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none text-sm focus:ring-2 focus:ring-orange-500"
              />
            </div>
          </div>
        </section>

        <section className="space-y-6">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-2">Dietary Standards</h3>
          <div className="space-y-6">
            <div className="flex flex-wrap gap-2">
              {RELIGIOUS_DIETS.map(d => (
                <button 
                  key={d}
                  onClick={() => toggle('defaultDietaryRestrictions', d)}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${form.defaultDietaryRestrictions.includes(d) ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-slate-50 text-slate-600 border-slate-200 hover:border-blue-200'}`}
                >
                  {d}
                </button>
              ))}
            </div>

            {form.isKosher && (
              <div className="p-6 bg-blue-50/50 rounded-3xl border border-blue-100 animate-in slide-in-from-top-4 space-y-4">
                <p className="text-sm font-bold text-blue-800">Kosher Defaults</p>
                <div>
                  <label className="block text-[10px] font-black text-blue-400 uppercase mb-2">Observance Level</label>
                  <div className="flex flex-wrap gap-2">
                    {KOSHER_STANDARDS.map(s => (
                      <button
                        key={s}
                        onClick={() => update('kosherStandard', s)}
                        className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${form.kosherStandard === s ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-blue-300'}`}
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}

            <div className="flex flex-wrap gap-2">
              {HEALTH_DIETS.map(d => (
                <button 
                  key={d}
                  onClick={() => toggle('defaultDietaryRestrictions', d)}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${form.defaultDietaryRestrictions.includes(d) ? 'bg-emerald-600 text-white border-emerald-600 shadow-md' : 'bg-slate-50 text-slate-600 border-slate-200 hover:border-emerald-200'}`}
                >
                  {d}
                </button>
              ))}
            </div>
          </div>
        </section>

        <button 
          onClick={handleSave}
          className="w-full bg-slate-900 text-white font-black py-5 rounded-[2rem] hover:bg-orange-600 transition-all shadow-xl shadow-slate-200 transform hover:scale-[1.02]"
        >
          Save All Preferences
        </button>
      </div>
    </div>
  );
};

export default Settings;

