    allergies: [],
    customAllergies: '',
    dietaryRestrictions: settings.defaultDietaryRestrictions,
    customHealthGoals: '',
    customReligious: '',
    ingredients: '',
    pantryStaples: [],
    equipment: settings.defaultEquipment,
    avoidList: [],
    isKosher: settings.isKosher,
    kosherType: 'Pareve',
    skillLevel: settings.skillLevel,
    favoriteChef: settings.favoriteChef
  });

  const updateForm = (key: keyof WizardState, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const toggleList = (key: 'cuisines' | 'dietaryRestrictions' | 'equipment' | 'allergies' | 'pantryStaples', item: string) => {
    const list = [...(formData[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) {
      list.splice(index, 1);
      if (item === 'Kosher' && key === 'dietaryRestrictions') updateForm('isKosher', false);
    } else {
      list.push(item);
      if (item === 'Kosher' && key === 'dietaryRestrictions') updateForm('isKosher', true);
    }
    updateForm(key, list);
  };

  const handleSelectAllStaples = () => {
    if (formData.pantryStaples.length === PANTRY_STAPLES.length) {
      updateForm('pantryStaples', []);
    } else {
      updateForm('pantryStaples', [...PANTRY_STAPLES]);
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateForm('ingredientPhoto', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    onLoading(true);
    try {
      const results = await generateRecipes(formData);
      onComplete(results);
    } catch (err: any) {
      onError(err.message || 'Something went wrong');
    } finally {
      onLoading(false);
    }
  };

  const hasMeatInput = MEAT_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k));
  const hasVeggieInput = VEGGIE_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k) || formData.pantryStaples.some(s => s.toLowerCase().includes(k)));
  const showVeggieNudge = hasMeatInput && !hasVeggieInput && formData.ingredients.trim().length > 3;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100 max-w-2xl mx-auto">
      <div className="h-2 bg-slate-100 flex">
        {[1, 2, 3].map(i => (
          <div key={i} className={`h-full flex-1 transition-all duration-500 ${step >= i ? 'bg-orange-500' : 'bg-transparent'}`} />
        ))}
      </div>

      <div className="p-8">
        {step === 1 && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm font-black">1</span>
              Preferences
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Meal Type</label>
                <div className="flex flex-wrap gap-2">
                  {MEAL_TYPES.map(m => (
                    <button 
                      key={m}
                      onClick={() => updateForm('mealType', m)}
                      className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${formData.mealType === m ? 'bg-orange-600 border-orange-600 text-white shadow-md' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {m.charAt(0).toUpperCase() + m.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Servings</label>
                <input 
                  type="number" min="1" max="20"
                  value={formData.servings}
                  onChange={(e) => updateForm('servings', parseInt(e.target.value))}
                  className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Time Available (mins)</label>
                <input 
                  type="range" min="10" max="180" step="5"
                  value={formData.timeAvailable}
                  onChange={(e) => updateForm('timeAvailable', parseInt(e.target.value))}
                  className="w-full accent-orange-500"
                />
                <div className="text-right text-xs font-bold text-orange-600 mt-1">{formData.timeAvailable} minutes</div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Spice Level</label>
                <div className="flex flex-wrap gap-2">
                  {SPICE_LEVELS.map(s => (
                    <button 
                      key={s}
                      onClick={() => updateForm('spiceLevel', s)}
                      className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.spiceLevel === s ? 'bg-orange-600 border-orange-600 text-white shadow-md' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-4">Cuisines (Select All that Apply)</label>
              <div className="space-y-4 max-h-60 overflow-y-auto pr-2 scrollbar-thin">
                {Object.entries(CUISINE_REGIONS).map(([region, items]) => (
                  <div key={region} className="space-y-2">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{region}</p>
                    <div className="flex flex-wrap gap-2">
                      {items.map(c => (
                        <button 
                          key={c}
                          onClick={() => toggleList('cuisines', c)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.cuisines.includes(c) ? 'bg-orange-100 border-orange-400 text-orange-700 shadow-sm' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                        >
                          {c}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="flex items-center gap-3">
              <input 
                type="checkbox" id="leftovers"
                checked={formData.leftovers}
                onChange={(e) => updateForm('leftovers', e.target.checked)}
                className="w-5 h-5 accent-orange-500"
              />
              <label htmlFor="leftovers" className="text-sm font-medium text-slate-700">Include leftovers guide?</label>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm font-black">2</span>
              Household & Diet
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Who's eating?</label>
                  <div className="flex flex-wrap gap-2">
                    {HOUSEHOLD_TYPES.map(h => (
                      <button 
                        key={h}
                        onClick={() => updateForm('household', h)}
                        className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${formData.household === h ? 'bg-slate-800 border-slate-800 text-white shadow-md' : 'border-slate-200 text-slate-600 hover:border-slate-300'}`}
                      >
                        {h.charAt(0).toUpperCase() + h.slice(1)}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-3">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Religious / Ethical</label>
                  <div className="flex flex-wrap gap-2">
                    {RELIGIOUS_DIETS.map(d => (
                      <button 
                        key={d}
                        onClick={() => toggleList('dietaryRestrictions', d)}
                        className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.dietaryRestrictions.includes(d) ? 'bg-blue-600 border-blue-600 text-white shadow-sm' : 'border-slate-200 text-slate-600 hover:border-blue-300'}`}
                      >
                        {d}
                      </button>
                    ))}
                  </div>
                  <input 
                    type="text"
                    value={formData.customReligious}
                    onChange={(e) => updateForm('customReligious', e.target.value)}
                    placeholder="Other religious requirements..."
                    className="w-full text-xs p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500"
                  />
                </div>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Top 10 Allergens</label>
                  <div className="grid grid-cols-2 gap-2 mb-3">
                    {COMMON_ALLERGENS.map(a => (
                      <button 
                        key={a}
                        onClick={() => toggleList('allergies', a)}
                        className={`text-left px-3 py-2 rounded-xl text-xs font-bold border transition-all flex items-center justify-between ${formData.allergies.includes(a) ? 'bg-red-50 border-red-300 text-red-700' : 'bg-white border-slate-100 text-slate-500 hover:border-red-200'}`}
                      >
                        {a}
                        {formData.allergies.includes(a) ? '🚫' : '⬜'}
                      </button>
                    ))}
                  </div>
                  <input 
                    type="text"
                    value={formData.customAllergies}
                    onChange={(e) => updateForm('customAllergies', e.target.value)}
                    placeholder="Other specific allergies..."
                    className="w-full text-xs p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-red-500"
                  />
                </div>
              </div>
            </div>

            {formData.isKosher && (
              <div className="p-6 bg-blue-50/50 rounded-3xl border border-blue-100 animate-in fade-in slide-in-from-top-2">
                <div className="text-center mb-4">
                  <p className="text-xs font-black text-blue-400 uppercase tracking-widest mb-1">Mandatory Kosher Category</p>
                  <p className="text-[10px] text-blue-400 italic">Select the category for this specific meal</p>
                </div>
                <div className="flex gap-2 bg-white p-2 rounded-2xl border border-blue-100 shadow-sm max-w-sm mx-auto">
                  {KOSHER_TYPES.map(t => (
                    <button 
                      key={t}
                      onClick={() => updateForm('kosherType', t)}
                      className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${formData.kosherType === t ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white text-slate-400 hover:bg-slate-50'}`}
                    >
                      {t}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="pt-4 border-t border-slate-100">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Health Goals</label>
              <div className="flex flex-wrap gap-2 mb-3">
                {HEALTH_DIETS.map(d => (
                  <button 
                    key={d}
                    onClick={() => toggleList('dietaryRestrictions', d)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.dietaryRestrictions.includes(d) ? 'bg-emerald-600 border-emerald-600 text-white shadow-sm' : 'border-slate-200 text-slate-600 hover:border-emerald-300'}`}
                  >
                    {d}
                  </button>
                ))}
              </div>
              <input 
                type="text"
                value={formData.customHealthGoals}
                onChange={(e) => updateForm('customHealthGoals', e.target.value)}
                placeholder="Other health goals (e.g. low sulfur, high magnesium)..."
                className="w-full text-xs p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-emerald-500"
              />
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm font-black">3</span>
              Pantry & Equipment
            </h2>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">What are we working with? (Snap or Type)</label>
              <div className="space-y-3">
                <textarea 
                  value={formData.ingredients}
                  onChange={(e) => updateForm('ingredients', e.target.value)}
                  placeholder="2 chicken breasts, 1 head of broccoli, soy sauce..."
                  className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 focus:outline-none resize-none shadow-inner bg-slate-50/50"
                />

                {showVeggieNudge && (
                  <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-2xl animate-in slide-in-from-top-2 shadow-sm">
                    <p className="text-emerald-800 text-sm font-medium">
                      🥗 <span className="font-bold">Balanced Meal Tip:</span> You have great protein options. Do you have any <span className="underline decoration-emerald-300 font-bold italic">fresh vegetables</span> (spinach, peppers, kale) to add color and health?
                    </p>
                  </div>
                )}

                <div className="flex flex-col gap-2">
                   <div className="flex items-center gap-4">
                    <label className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl cursor-pointer transition-colors text-sm font-semibold border border-slate-200">
                      <span className="text-lg">📷</span> {formData.ingredientPhoto ? 'Photo Added!' : 'Snap Ingredients'}
                      <input type="file" accept="image/*" onChange={handlePhotoUpload} className="hidden" />
                    </label>
                    {formData.ingredientPhoto && <button onClick={() => updateForm('ingredientPhoto', undefined)} className="text-red-500 text-xs font-bold underline">Remove photo</button>}
                  </div>
                  <div className="flex items-center gap-2 mt-1">
                    <span className="text-xs text-slate-400 font-bold italic uppercase tracking-tighter">Missing any Ingredients?</span>
                    <a href="https://amzn.to/3Og7iBH" target="_blank" rel="noopener noreferrer" className="text-xs font-black text-blue-600 hover:underline flex items-center gap-1">
                      🛒 Order on Amazon Fresh
                    </a>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <label className="block text-sm font-semibold text-slate-700">Pantry Staples</label>
                  {showStaples && (
                    <button 
                      onClick={handleSelectAllStaples}
                      className="text-[10px] font-black bg-slate-100 px-2 py-0.5 rounded border border-slate-200 hover:bg-slate-200 transition-colors uppercase"
                    >
                      {formData.pantryStaples.length === PANTRY_STAPLES.length ? 'Clear All' : 'Select All'}
                    </button>
                  )}
                </div>
                <button 
                  onClick={() => setShowStaples(!showStaples)}
                  className="text-xs font-bold text-orange-600 underline"
                >
                  {showStaples ? 'Hide Essentials' : 'Show Staples Checklist'}
                </button>
              </div>

              {showStaples && (
                <div className="bg-orange-50/30 p-4 rounded-2xl border border-orange-100 grid grid-cols-2 md:grid-cols-3 gap-2 animate-in fade-in">
                  {PANTRY_STAPLES.map(s => {
                    const link = STAPLE_LINKS[s] || STAPLE_LINKS['GENERAL'];
                    return (
                      <div key={s} className="flex items-center gap-1 group">
                        <button 
                          onClick={() => toggleList('pantryStaples', s)}
                          className={`flex-1 text-left px-3 py-1.5 rounded-lg text-xs font-medium border transition-all flex items-center gap-2 ${formData.pantryStaples.includes(s) ? 'bg-orange-600 border-orange-600 text-white shadow-sm' : 'bg-white border-slate-200 text-slate-500 hover:border-orange-200'}`}
                        >
                          <span className="text-sm">{formData.pantryStaples.includes(s) ? '✅' : '⬜'}</span> {s}
                        </button>
                        <a 
                          href={link} 
                          target="_blank" 
                          rel="noopener noreferrer" 
                          className="p-1 opacity-0 group-hover:opacity-100 transition-opacity bg-white border border-slate-200 rounded text-[10px] shadow-sm hover:bg-orange-50"
                          title={`Buy ${s} on Amazon`}
                        >
                          🛒
                        </a>
                      </div>
                    );
                  })}
                  <div className="col-span-full pt-2 border-t border-orange-100/50 mt-1">
                    <p className="text-[10px] text-orange-400 font-bold uppercase italic tracking-tight">
                      <a href="https://amzn.to/3Og7iBH" target="_blank" className="underline font-black">Stock Up on Amazon</a>
                    </p>
                  </div>
                </div>
              )}
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2 text-left">Kitchen Tools</label>
              <div className="flex flex-wrap gap-2">
                {COMMON_EQUIPMENT.map(e => (
                  <button 
                    key={e}
                    onClick={() => toggleList('equipment', e)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.equipment.includes(e) ? 'bg-slate-800 border-slate-800 text-white shadow-sm' : 'border-slate-200 text-slate-600 hover:border-orange-300'}`}
                  >
                    {e}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        <div className="mt-10 flex justify-between items-center pt-6 border-t border-slate-100">
          {step > 1 && (
            <button 
              onClick={() => setStep(s => s - 1)}
              className="text-slate-500 font-bold hover:text-slate-800 transition-colors"
            >
              Back
            </button>
          )}
          <div className="flex-1" />
          {step < 3 ? (
            <button 
              onClick={() => setStep(s => s + 1)}
              className="bg-orange-600 text-white font-black py-3 px-8 rounded-full shadow-lg shadow-orange-200 hover:bg-orange-700 transition-all"
            >
              Next Step
            </button>
          ) : (
            <button 
              onClick={handleSubmit}
              disabled={isLoading}
              className="bg-orange-600 text-white font-extrabold py-3 px-10 rounded-full shadow-lg shadow-orange-200 hover:bg-orange-700 transition-all disabled:opacity-50"
            >
              {isLoading ? 'Generating...' : 'Cook My Recipes!'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Wizard;

import React, { useState, useEffect } from 'react';
import { WizardState, GenerationResponse, AppSettings } from '../types';
import { MEAL_TYPES, EFFORT_LEVELS, SPICE_LEVELS, HOUSEHOLD_TYPES, RELIGIOUS_DIETS, HEALTH_DIETS, CUISINE_REGIONS, COMMON_EQUIPMENT, KOSHER_TYPES, PANTRY_STAPLES, COMMON_ALLERGENS, STAPLE_LINKS } from '../constants';
import { generateRecipes } from '../lib/recipeModel';

interface WizardProps {
  settings: AppSettings;
  onComplete: (data: GenerationResponse) => void;
  onLoading: (loading: boolean) => void;
  onError: (error: string) => void;
  isLoading: boolean;
}

const MEAT_KEYWORDS = ['beef', 'chicken', 'steak', 'lamb', 'meat', 'turkey', 'veal', 'ground beef', 'ribs', 'bacon', 'ham', 'salmon', 'tuna', 'fish'];
const VEGGIE_KEYWORDS = ['broccoli', 'carrot', 'spinach', 'kale', 'pepper', 'onion', 'garlic', 'potato', 'vegetable', 'greens', 'zucchini', 'tomato', 'cabbage', 'lettuce', 'cucumber', 'cauliflower', 'asparagus', 'beans'];

const Wizard: React.FC<WizardProps> = ({ settings, onComplete, onLoading, onError, isLoading }) => {
  const [step, setStep] = useState(1);
  const [showStaples, setShowStaples] = useState(false);
  const [formData, setFormData] = useState<WizardState>({
    mealType: 'dinner',
    servings: 2,
    leftovers: false,
    timeAvailable: 30,
    effortLevel: 'Medium',
    spiceLevel: settings.defaultSpice,
    cuisines: settings.defaultCuisines,
    household: settings.defaultHousehold,
    allergies: [],
    customAllergies: '',
    dietaryRestrictions: settings.defaultDietaryRestrictions,
    customHealthGoals: '',
    customReligious: '',
    ingredients: '',
    pantryStaples: [],
    equipment: settings.defaultEquipment,
    avoidList: [],
    isKosher: settings.isKosher,
    kosherType: 'Pareve',
    skillLevel: settings.skillLevel,
    favoriteChef: settings.favoriteChef
  });

  const updateForm = (key: keyof WizardState, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const toggleList = (key: 'cuisines' | 'dietaryRestrictions' | 'equipment' | 'allergies' | 'pantryStaples', item: string) => {
    const list = [...(formData[key] as string[])];
    const index = list.indexOf(item);
    if (index > -1) {
      list.splice(index, 1);
      if (item === 'Kosher' && key === 'dietaryRestrictions') updateForm('isKosher', false);
    } else {
      list.push(item);
      if (item === 'Kosher' && key === 'dietaryRestrictions') updateForm('isKosher', true);
    }
    updateForm(key, list);
  };

  const handleSelectAllStaples = () => {
    if (formData.pantryStaples.length === PANTRY_STAPLES.length) {
      updateForm('pantryStaples', []);
    } else {
      updateForm('pantryStaples', [...PANTRY_STAPLES]);
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateForm('ingredientPhoto', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    onLoading(true);
    try {
      const results = await generateRecipes(formData);
      onComplete(results);
    } catch (err: any) {
      onError(err.message || 'Something went wrong');
    } finally {
      onLoading(false);
    }
  };

  const hasMeatInput = MEAT_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k));
  const hasVeggieInput = VEGGIE_KEYWORDS.some(k => formData.ingredients.toLowerCase().includes(k) || formData.pantryStaples.some(s => s.toLowerCase().includes(k)));
  const showVeggieNudge = hasMeatInput && !hasVeggieInput && formData.ingredients.trim().length > 3;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100 max-w-2xl mx-auto">
      <div className="h-2 bg-slate-100 flex">
        {[1, 2, 3].map(i => (
          <div key={i} className={`h-full flex-1 transition-all duration-500 ${step >= i ? 'bg-orange-500' : 'bg-transparent'}`} />
        ))}
      </div>

      <div className="p-8">
        {step === 1 && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              <span className="bg-orange-100 text-orange-600 w-8 h-8 rounded-full flex items-center justify-center text-sm font-black">1</span>
              General Details
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Meal Type</label>
                <div className="flex flex-wrap gap-2">
                  {MEAL_TYPES.map(m => (
                    <button 
